SELECT iteration_id, MAX(log_date) AS latest_log_date
FROM iteration_logs
GROUP BY iteration_id;

SELECT rmse
FROM training_iterations
WHERE model_id = 1 AND state = 'COMPLETE';

SELECT log_message
FROM iteration_logs
WHERE iteration_id = 1;

SELECT AVG(rmse) AS avg_rmse
FROM training_iterations
WHERE model_id = 1;
